class Solution:
    def luckyNumbers(self, matrix):
        row_mins = {min(row) for row in matrix}
        col_maxs = {max(matrix[r][c] for r in range(len(matrix))) for c in range(len(matrix[0]))}
        return list(row_mins & col_maxs)

