var luckyNumbers = function(matrix) {
    const m = matrix.length, n = matrix[0].length;
    const rowMins = new Set(matrix.map(row => Math.min(...row)));
    const colMaxs = new Set();
    for (let c = 0; c < n; c++) {
        let mx = -Infinity;
        for (let r = 0; r < m; r++) mx = Math.max(mx, matrix[r][c]);
        colMaxs.add(mx);
    }
    const result = [];
    for (const v of rowMins) if (colMaxs.has(v)) result.push(v);
    return result;
};
